setTimeout(() => setNewRowId(null), 700);
```

With:
```javascript
setNewRowIds(prev => new Set([...prev, res.data.id]));
setTimeout(() => {
  setNewRowIds(prev => {
    const next = new Set(prev);
    next.delete(res.data.id);
    return next;
  });
}, 700);
```

